<template>
    <!-- component is reached from 'activeComponent' computed -->
    <component :is="activeComponent" />
</template>
<script lang="ts">
import { defineComponent, computed } from 'vue'

import { getAllComponents } from '../components/actions';


export default defineComponent({
    name: 'ActionPage',
    components: {
        ...getAllComponents(),
    },
    props: {
        // customComponents: {
        //     type: Object,
        //     default: () => ({}),
        // },
    },
    computed: {
        activeComponent() {
            // Merge custom components with any default components
            const components = {
                ...this.$options.components,
                // ...this.customComponents,
            };
            return components[this.$route.params.type];
        },
    },
})
</script>
